import unicodedata
def fingerprint(s):
    return unicodedata.normalize("NFC", s).casefold().strip()
print(fingerprint("  MAÑANA  "), fingerprint("mañana"))

# dual skeptic-H1 · S07-T1-B-E2
def split_name(raw):
    toks = raw.split()
    if len(toks) < 2:
        return {"raw": raw, "status": "review", "given": None, "apellidos": None}
    return {"raw": raw, "status": "ok", "given": " ".join(toks[:-2]) if len(toks) > 2 else toks[0],
            "apellidos": toks[-2:] if len(toks) >= 2 else toks}
print(split_name("Ana"))
print(split_name("Ana Quispe Huamán"))

